// Returns true if a string looks like a code/reference rather than a title
// e.g. "11033-01", "ZV-KDZ_3-1" — short, digit-heavy, no German words
function looksLikeReferenceCode(s) {
  if (!s || s.length > 60) return false;
  return /^[\d\s\-_.A-Z]{1,60}$/i.test(s) && /\d/.test(s) && !/[a-zäöüÄÖÜ]{5,}/.test(s);
}

// Pick first non-reference-code value from a list of candidates
function bestTitle(candidates, fallback) {
  for (const c of candidates) {
    const s = (c || '').trim();
    if (s && !looksLikeReferenceCode(s)) return s;
  }
  return fallback || 'Leistungsverzeichnis';
}

/* Build tender row from pre-parsed GAEB payload */
const input = $json;
const gaebFiles = input.gaeb_files || [];

function deriveTrade(g) {
  const entries = g?.bill_of_quantities?.entries || [];
  for (const e of entries) {
    if (e.type === 'item' && e.category_path?.length > 0) return e.category_path[0];
  }
  return null;
}

function dataPhase(g) {
  const num = parseInt(g?.metadata?.data_phase, 10);
  return isNaN(num) ? null : num;
}

function serializeGaebText(gaebFiles) {
  const lines = [];
  for (const g of gaebFiles) {
    if (g._error) continue;
    const proj = bestTitle([g.project?.name, g.project?.label, g.bill_of_quantities?.label, g.bill_of_quantities?.name, (g.award_description || [])[0]?.outline], g.award_no ? 'Ausschreibung ' + g.award_no : 'Leistungsverzeichnis');
    const owner = g.owner?.name || g.owner?.bauherr || null;
    lines.push('# ' + proj);
    if (owner) lines.push('Auftraggeber: ' + owner);
    if (g.award_no) lines.push('Vergabe-Nr.: ' + g.award_no);
    lines.push('');
    for (const block of (g.award_description || [])) {
      if (block.outline) lines.push('## ' + block.outline);
      if (block.detail) lines.push(block.detail);
      lines.push('');
    }
    const entries = g.bill_of_quantities?.entries || [];
    const seenCats = new Set();
    let shown = 0;
    for (const e of entries) {
      if (e.type === 'item' && shown < 40) {
        const catKey = (e.category_path || []).slice(0, -1).join(' > ');
        if (catKey && !seenCats.has(catKey)) {
          seenCats.add(catKey);
          lines.push('\n### ' + catKey);
        }
        lines.push('- [' + e.position + '] ' + (e.short_text || '') + (e.unit ? ' (' + e.quantity + ' ' + e.unit + ')' : ''));
        if (e.long_text) lines.push('  ' + e.long_text.split('\n')[0].slice(0, 120));
        shown++;
      }
    }
    lines.push('\n(' + (g.bill_of_quantities?.total_items || 0) + ' Positionen gesamt)');
  }
  return lines.join('\n');
}


// When all GAEB files have _error, extract descriptive folder names from
// archive_summary.other_names (paths like "heftung1/Verlegung XYZ/file.D83")
// The parent folder of a .D83 file is often the best available project description.
function titleFromArchiveFolders(gaebFiles, archiveSummary) {
  // Only use this when the primary file has an error
  const primary = gaebFiles[0];
  if (!primary || !primary._error) return null;

  const otherNames = (archiveSummary && archiveSummary.other_names) || [];
  const gaebLike = ['.d81','.d82','.d83','.d84','.d85','.d86','.x81','.x82','.x83','.x84','.x85','.x86'];
  const folders = new Set();

  for (const p of otherNames) {
    const ext = ('.' + p.split('.').pop()).toLowerCase();
    if (gaebLike.includes(ext)) {
      const parts = p.replace(/\\/g, '/').split('/');
      // Take the parent folder (not the archive root like "heftung1")
      if (parts.length >= 3) {
        const folder = parts[parts.length - 2];
        // Skip generic folder names
        if (folder && !/^heftung|^los[\s\d]/i.test(folder) && folder.length > 4) {
          folders.add(folder);
        }
      } else if (parts.length === 2) {
        // file directly in heftung — use filename without extension and number prefix
        const stem = parts[1].replace(/\.[^.]+$/, '').replace(/^\d+[-_]/, '');
        if (stem.length > 4) folders.add(stem);
      }
    }
  }

  if (folders.size === 0) return null;
  return Array.from(folders).join(' / ');
}

const primary = gaebFiles.find(g => parseInt(g?.metadata?.data_phase, 10) === 82) || gaebFiles[0] || {};
const totalItems = gaebFiles.reduce((s, g) => s + (g.bill_of_quantities?.total_items || 0), 0);

// Extract top-level LV positions for Type 1 display
const gaebPositions = gaebFiles.flatMap(g => {
  if (g._error) return [];
  const entries = g.bill_of_quantities?.entries || [];
  return entries
    .filter(e => e.type === 'item')
    .slice(0, 200)
    .map(e => ({
      id: e.position || e.id || '',
      short_text: e.short_text || '',
      long_text: (e.long_text || '').slice(0, 200),
      quantity: e.quantity || null,
      unit: e.unit || null,
      category_path: e.category_path || [],
      gaeb_phase: parseInt(g.metadata?.data_phase, 10) || null,
    }));
});

return [{ json: {
  id: input.tender_id,
  org_id: input.org_id,
  user_id: input.user_id,
  title: bestTitle([
    primary.project?.name,
    primary.project?.label,
    primary.bill_of_quantities?.label,
    primary.bill_of_quantities?.name,
    (primary.award_description || [])[0]?.outline,
    titleFromArchiveFolders(gaebFiles, input.archive_summary),
  ], (primary.award_no ? 'Ausschreibung ' + primary.award_no : null) || (primary.owner?.city ? 'Leistungsverzeichnis – ' + primary.owner?.city : null) || 'Leistungsverzeichnis'),
  buyer: primary.owner?.name || primary.owner?.bauherr || null,
  region: primary.owner?.city || null,
  trade_category: deriveTrade(primary),
  gaeb_phase: parseInt(primary.metadata?.data_phase, 10) || null,
  item_count: totalItems,
  lot_count: gaebFiles.length,
  source_type: 'gaeb',
  source_filename: input.source_filename || '',
  has_plans: input.has_plans || false,
  raw_gaeb_json: gaebFiles,
  gaeb_positions: gaebPositions,
  pdf_text: serializeGaebText(gaebFiles),
  processing_status: 'metadata_ready',
  deadline: primary.metadata?.deadline || primary.metadata?.award_deadline || primary.award_deadline || null
} }];
